sys_script_include.script:
var AROPCheckLibrary_AIOPS = Class.create();
AROPCheckLibrary_AIOPS.prototype = {
    initialize: function() {},
    _count: function(table, query) { var gr = new GlideRecord(table); if (query) gr.addEncodedQuery(query); gr.query(); return gr.getRowCount(); },
    _pct: function(num, den) { return den > 0 ? Math.round((num/den)*100) : 0; },
    CHK0000443: function() {
        try {
            return (function(checkDef, dateFilter) {
    var checkPlugin = (function checkPlugin(storeScope, pluginSource) {    var result = { found: false, version: "", table: "" };    try {        var saGR = new GlideRecord("sys_store_app");        saGR.addQuery("scope", storeScope);        saGR.setLimit(1);        saGR.query();        if (saGR.next()) {            result.found = true;            result.version = saGR.getValue("version") || "";            result.table = "sys_store_app";            return result;        }    } catch(e1) {}    if (pluginSource) {        try {            var spGR = new GlideRecord("sys_plugins");            spGR.addQuery("source", pluginSource);            spGR.addQuery("active", true);            spGR.setLimit(1);            spGR.query();            if (spGR.next()) {                result.found = true;                result.version = spGR.getValue("version") || "";                result.table = "sys_plugins";                return result;            }        } catch(e2) {}    }    return result;});
    var result = checkPlugin("sn_itom_gen_ai", "sn_itom_gen_ai");
    if (result.found) {
        return {
            status: "ready",
            actualValue: "Now Assist for TSOM/ITOM (" + "sn_itom_gen_ai" + ") installed | version: " + result.version + " | source: " + result.table,
            finding: "Now Assist for TSOM/ITOM is installed. AI-assisted event correlation, alert grouping, and impact analysis capabilities are available."
        };
    } else {
        return {
            status: "not_ready",
            actualValue: "Now Assist for TSOM/ITOM (sn_itom_gen_ai) not found in sys_store_app or sys_plugins",
            finding: "Now Assist for TSOM/ITOM (sn_itom_gen_ai) not found. AI-assisted event correlation and alert grouping are unavailable."
        };
    }
})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000443: ' + e.message };
        }
    },
    CHK0000444: function() {
        try {
            return (function(checkDef, dateFilter) {
    var checkPlugin = (function checkPlugin(storeScope, pluginSource) {    var result = { found: false, version: "", table: "" };    try {        var saGR = new GlideRecord("sys_store_app");        saGR.addQuery("scope", storeScope);        saGR.setLimit(1);        saGR.query();        if (saGR.next()) {            result.found = true;            result.version = saGR.getValue("version") || "";            result.table = "sys_store_app";            return result;        }    } catch(e1) {}    if (pluginSource) {        try {            var spGR = new GlideRecord("sys_plugins");            spGR.addQuery("source", pluginSource);            spGR.addQuery("active", true);            spGR.setLimit(1);            spGR.query();            if (spGR.next()) {                result.found = true;                result.version = spGR.getValue("version") || "";                result.table = "sys_plugins";                return result;            }        } catch(e2) {}    }    return result;});
    var result = checkPlugin("com.snc.service_operations_workspace", "com.snc.service_operations_workspace");
    if (!result.found) {
        var gr = new GlideRecord("sys_scope");
        gr.addQuery("scope", "sn_sow_itom");
        gr.addQuery("active", true);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) { result.found = true; result.table = "sys_scope"; }
    }
    if (result.found) {
        return { status: "ready",
            actualValue: "Service Operations Workspace is active | source: " + result.table,
            finding: "SOW active -- Now Assist TSOM AI insights visible to operations team." };
    } else {
        return { status: "needs_attention",
            actualValue: "Service Operations Workspace not found",
            finding: "Service Operations Workspace not active. Now Assist TSOM alert summaries and AI recommendations require SOW to surface to operators." };
    }
})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000444: ' + e.message };
        }
    },
    CHK0000445: function() {
        try {
            return (function(){var gr=new GlideRecord("em_alert_correlation_rule");gr.addQuery("active",true);gr.query();var n=gr.getRowCount();return{status:n>=5?"ready":"needs_attention",actualValue:n+" active alert correlation rules",finding:n<5?"Only "+n+" correlation rules. Now Assist TSOM AI grouping requires correlation rules as the foundation.":n+" active correlation rules -- Now Assist has the foundation for AI-assisted event grouping."};})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000445: ' + e.message };
        }
    },
    CHK0000446: function() {
        try {
            return (function(){try{if(!gs.tableExists("sn_si_trigger")){return{status:"needs_validation",actualValue:"Table not found",finding:"sn_si_trigger table not present -- manual verification required. Confirm Runbook Automation is installed and active."};}var gr=new GlideRecord("sn_si_trigger");gr.addQuery("active",true);gr.query();var n=gr.getRowCount();return{status:n>=10?"ready":"needs_attention",actualValue:n+" active runbook triggers",finding:n<10?"Only "+n+" active runbook triggers. Now Assist TSOM AI Agents use runbook routing rules for automated remediation -- low count limits AI action scope.":n+" active runbook triggers -- Now Assist TSOM AI Agents can execute automated remediation.";};}catch(e){return{status:"needs_validation",actualValue:"Check failed",finding:"Script execution error: "+e.message};};})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000446: ' + e.message };
        }
    },
    CHK0000447: function() {
        try {
            return (function(){var d=new GlideDateTime();d.addDaysUTC(-30);var gr=new GlideRecord("em_alert");gr.addQuery("sys_created_on",">=",d.getValue());gr.query();var n=gr.getRowCount();var gr2=new GlideRecord("em_alert");gr2.addQuery("state","Closed");gr2.query();var closed=gr2.getRowCount();var tot=new GlideRecord("em_alert");tot.query();var total=tot.getRowCount();var pct=total>0?Math.round((closed/total)*100):0;return{status:(n<10000&&pct>=50)?"ready":"needs_attention",actualValue:n+" alerts last 30 days | "+pct+"% closed",finding:"Alert volume: "+n+" in 30 days with "+pct+"% closure rate. "+(n>=10000||pct<50?"High noise environment degrades Now Assist TSOM event correlation accuracy.":"Alert noise ratio acceptable for Now Assist TSOM AI correlation.")};})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000447: ' + e.message };
        }
    },
    CHK0000448: function() {
        try {
            return (function(){var gr=new GlideRecord("cmdb_ci_service");gr.addQuery("active",true);gr.addQuery("has_map",true);gr.query();var mapped=gr.getRowCount();var gr2=new GlideRecord("cmdb_ci_service");gr2.addQuery("active",true);gr2.query();var total=gr2.getRowCount();return{status:mapped>=5?"ready":"needs_attention",actualValue:mapped+" services with maps of "+total+" total",finding:mapped<5?"Only "+mapped+" services have service maps. Now Assist TSOM uses maps for AI impact analysis -- incomplete maps limit assessment depth.":mapped+" services with maps -- Now Assist TSOM has service context for AI impact analysis."};})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000448: ' + e.message };
        }
    },
    CHK0000449: function() {
        try {
            return (function(){var gr=new GlideRecord("sa_pattern");gr.addQuery("active",true);gr.query();var n=gr.getRowCount();return{status:n>=50?"ready":"needs_attention",actualValue:n+" active service mapping patterns",finding:n<50?"Only "+n+" active mapping patterns. Now Assist TSOM topology-based impact analysis requires comprehensive pattern coverage.":n+" active patterns -- Now Assist TSOM has topology foundation for AI impact traversal."};})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000449: ' + e.message };
        }
    },
    CHK0000450: function() {
        try {
            return (function(){var gr=new GlideRecord("em_alert");gr.addNotNullQuery("incident");gr.query();var linked=gr.getRowCount();var gr2=new GlideRecord("em_alert");gr2.query();var total=gr2.getRowCount();var pct=total>0?Math.round((linked/total)*100):0;return{status:pct>=10?"ready":"needs_attention",actualValue:pct+"% of alerts generated incidents ("+linked+"/"+total+")",finding:pct<10?"Only "+pct+"% alert-to-incident conversion. Now Assist TSOM has no historical alert-incident linkage for AI remediation learning.":pct+"% alert-to-incident conversion -- Now Assist TSOM has historical data for AI pattern learning."};})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000450: ' + e.message };
        }
    },
    CHK0000451: function() {
        try {
            return (function(){var gr=new GlideRecord("ecc_agent");gr.addQuery("status","Up");gr.query();var up=gr.getRowCount();var gr2=new GlideRecord("ecc_agent");gr2.query();var total=gr2.getRowCount();return{status:up>=1?"ready":"needs_attention",actualValue:total+" MID Servers | "+up+" Up",finding:up<1?"No MID Servers Up. Now Assist TSOM AI Agent-triggered probes and remediation actions require available MID Servers.":up+" MID Servers Up -- Now Assist TSOM AI Agent actions can execute."};})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000451: ' + e.message };
        }
    },
    CHK0000452: function() {
        try {
            return (function(checkDef, dateFilter) {
    var checkPlugin = (function checkPlugin(storeScope, pluginSource) {    var result = { found: false, version: "", table: "" };    try {        var saGR = new GlideRecord("sys_store_app");        saGR.addQuery("scope", storeScope);        saGR.setLimit(1);        saGR.query();        if (saGR.next()) {            result.found = true;            result.version = saGR.getValue("version") || "";            result.table = "sys_store_app";            return result;        }    } catch(e1) {}    if (pluginSource) {        try {            var spGR = new GlideRecord("sys_plugins");            spGR.addQuery("source", pluginSource);            spGR.addQuery("active", true);            spGR.setLimit(1);            spGR.query();            if (spGR.next()) {                result.found = true;                result.version = spGR.getValue("version") || "";                result.table = "sys_plugins";                return result;            }        } catch(e2) {}    }    return result;});
    var result = checkPlugin("com.glide.agent_workspace", "com.glide.agent_workspace");
    // Functional fallback: check sys_scope
    if (!result.found) {
        var gr = new GlideRecord("sys_scope");
        gr.addQuery("scope", "CONTAINS", "agent_workspace");
        gr.addQuery("active", true);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) { result.found = true; result.table = "sys_scope"; }
    }
    if (result.found) {
        return { status: "ready",
            actualValue: "Agent Workspace is active | source: " + result.table,
            finding: "Agent Workspace active -- Now Assist TSOM AI insights visible to operators." };
    } else {
        return { status: "needs_attention",
            actualValue: "Agent Workspace not found",
            finding: "Agent Workspace not active. Now Assist TSOM alert summaries and AI recommendations require Agent Workspace." };
    }
})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000452: ' + e.message };
        }
    },
    CHK0000453: function() {
        try {
            return (function(){var gr=new GlideRecord("sys_script");gr.addQuery("collection","em_alert");gr.addQuery("active",true);gr.addEncodedQuery("sys_created_byNOT INglide.maint,system,admin,fred.luddy");gr.query();var n=gr.getRowCount();return{status:n<=10?"ready":"needs_attention",actualValue:n+" custom BRs on em_alert",finding:"TSOM customization risk: "+n+" custom BRs. "+(n>10?"High customization increases conflict risk with Now Assist TSOM AI correlation.":"Risk within acceptable range.")};})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000453: ' + e.message };
        }
    },
    CHK0000454: function() {
        try {
            return (function(){var gr=new GlideRecord("cmn_schedule_maintenance");gr.query();var n=gr.getRowCount();return{status:n>=5?"ready":"needs_attention",actualValue:n+" maintenance schedules defined",finding:n<5?"Only "+n+" maintenance schedules. Unscheduled maintenance generates false-positive alerts that degrade Now Assist TSOM AI correlation accuracy.":n+" maintenance schedules -- false-positive alert pollution is controlled."};})();
        } catch(e) {
            return { status: 'needs_validation', actualValue: 'Script error: ' + e.message, finding: 'Error in CHK0000454: ' + e.message };
        }
    },
    type: 'AROPCheckLibrary_AIOPS'
};
